// Extract escalation data from VAPI tool call payload
const body = $input.first().json.body;

if (!body || !body.message) {
  throw new Error('Invalid VAPI webhook payload: missing body.message');
}

const message = body.message;
const toolCallList = message.toolCallList;

if (!toolCallList || toolCallList.length === 0) {
  throw new Error('No tool calls in VAPI message');
}

const toolCall = toolCallList[0];
const args = toolCall.function?.arguments || toolCall.arguments || {};
const parsedArgs = typeof args === 'string' ? JSON.parse(args) : args;

const now = new Date();

return [{
  json: {
    toolCallId: toolCall.id,
    callerName: parsedArgs.caller_name || 'Unknown',
    callerEmail: parsedArgs.caller_email || '',
    preferredTime: parsedArgs.preferred_time || 'Not specified',
    category: parsedArgs.category || 'Other',
    escalationReason: parsedArgs.escalation_reason || 'No reason provided',
    callId: parsedArgs.call_id || message.call?.id || '',
    timestamp: now.toISOString(),
    timestampReadable: now.toLocaleString('en-NG', { timeZone: 'Africa/Lagos' })
  }
}];

// Format the success response back to VAPI
const data = $('Extract Escalation Data').first().json;

return [{
  json: {
    results: [
      {
        toolCallId: data.toolCallId,
        result: `Thank you, ${data.callerName}. Your request has been logged and a member of the RelayPay support team will contact you at ${data.callerEmail} at your preferred time: ${data.preferredTime}. Is there anything else before we end the call?`
      }
    ]
  }
}];

